#include <stdio.h>
#include <limits.h>

int kadane(int *arr, int n) {
    int max_sofar = arr[0];
    int cur_max = arr[0];
    for (int i = 1; i < n; ++i) {
        cur_max = (arr[i] > cur_max + arr[i]) ? arr[i] : cur_max + arr[i];
        if (cur_max > max_sofar) max_sofar = cur_max;
    }
    return max_sofar;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int M, N; scanf("%d %d", &M, &N);
        int mat[100][100];
        for (int i = 0; i < M; ++i)
            for (int j = 0; j < N; ++j)
                scanf("%d", &mat[i][j]);
        int best = INT_MIN;
        int temp[100];
        for (int top = 0; top < M; ++top) {
            for (int i = 0; i < N; ++i) temp[i] = 0;
            for (int bottom = top; bottom < M; ++bottom) {
                for (int col = 0; col < N; ++col)
                    temp[col] += mat[bottom][col];
                int cur = kadane(temp, N);
                if (cur > best) best = cur;
            }
        }
        printf("%d\n", best);
    }
    return 0;
}

