#include <bits/stdc++.h>
using namespace std;

int kadane(const vector<int>& a) {
    int max_sofar = a[0], cur = a[0];
    for (size_t i = 1; i < a.size(); ++i) {
        cur = max(a[i], cur + a[i]);
        max_sofar = max(max_sofar, cur);
    }
    return max_sofar;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int M, N; cin >> M >> N;
        vector<vector<int>> mat(M, vector<int>(N));
        for (int i = 0; i < M; ++i)
            for (int j = 0; j < N; ++j)
                cin >> mat[i][j];
        int best = INT_MIN;
        vector<int> temp(N);
        for (int top = 0; top < M; ++top) {
            fill(temp.begin(), temp.end(), 0);
            for (int bottom = top; bottom < M; ++bottom) {
                for (int col = 0; col < N; ++col)
                    temp[col] += mat[bottom][col];
                best = max(best, kadane(temp));
            }
        }
        cout << best << '\n';
    }
    return 0;
}

