import sys

def kadane(arr):
    max_sofar = arr[0]
    cur = arr[0]
    for x in arr[1:]:
        cur = max(x, cur + x)
        max_sofar = max(max_sofar, cur)
    return max_sofar

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        M = int(next(it)); N = int(next(it))
        mat = [[int(next(it)) for _ in range(N)] for __ in range(M)]
        best = -10**18
        temp = [0]*N
        for top in range(M):
            temp = [0]*N
            for bottom in range(top, M):
                for col in range(N):
                    temp[col] += mat[bottom][col]
                best = max(best, kadane(temp))
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

